@page "/apply"
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<h1>Job Application</h1>

@* Step Indicator Bar *@
<div class="step-indicator">
    @for (int i = 0; i < stepNames.Length; i++)
    {
        var stepIndex = i;
        var cssClass = GetStepClass(stepIndex);
        <div class="step @cssClass" @onclick="() => GoToStep(stepIndex)">
            <div class="step-circle">
                @if (stepIndex < currentStep)
                {
                    <span>&#10003;</span>
                }
                else
                {
                    <span>@(stepIndex + 1)</span>
                }
            </div>
            <div class="step-label">@stepNames[stepIndex]</div>
        </div>
        @if (i < stepNames.Length - 1)
        {
            <div class="step-connector"></div>
        }
    }
</div>

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger">@errorMessage</div>
}

@* Step Content *@
@if (currentStep == 0)
{
    <h2>Personal Information</h2>
    <div class="form-group">
        <label>Full Name *</label>
        <input type="text" class="form-control" @bind="fullName" />
    </div>
    <div class="form-group">
        <label>Email *</label>
        <input type="email" class="form-control" @bind="email" />
    </div>
    <div class="form-group">
        <label>Phone *</label>
        <input type="tel" class="form-control" @bind="phone" />
    </div>
    <div class="form-group">
        <label>Address *</label>
        <input type="text" class="form-control" @bind="address" />
    </div>
    <div class="form-actions">
        <button class="btn btn-primary" @onclick="NextStep" disabled="@isProcessing">
            @if (isProcessing) { <span>Validating...</span> } else { <span>Next</span> }
        </button>
    </div>
}
else if (currentStep == 1)
{
    <h2>Work History</h2>
    @for (int i = 0; i < workEntries.Count; i++)
    {
        var index = i;
        <div class="work-entry">
            <h4>Position @(index + 1)</h4>
            @if (workEntries.Count > 1)
            {
                <button class="btn btn-danger btn-sm" @onclick="() => RemoveWorkEntry(index)">Remove</button>
            }
            <div class="form-group">
                <label>Company *</label>
                <input type="text" class="form-control" @bind="workEntries[index].Company" />
            </div>
            <div class="form-group">
                <label>Job Title *</label>
                <input type="text" class="form-control" @bind="workEntries[index].Title" />
            </div>
            <div class="form-group">
                <label>Start Date *</label>
                <input type="date" class="form-control" @bind="workEntries[index].StartDate" />
            </div>
            <div class="form-group">
                <label>
                    <input type="checkbox" @bind="workEntries[index].IsCurrent" /> Currently working here
                </label>
            </div>
            @if (!workEntries[index].IsCurrent)
            {
                <div class="form-group">
                    <label>End Date</label>
                    <input type="date" class="form-control" @bind="workEntries[index].EndDate" />
                </div>
            }
            <div class="form-group">
                <label>Description</label>
                <textarea class="form-control" @bind="workEntries[index].Description"></textarea>
            </div>
        </div>
    }
    <button class="btn btn-secondary" @onclick="AddWorkEntry">Add Another Position</button>
    <div class="form-actions">
        <button class="btn btn-outline-secondary" @onclick="PreviousStep">Back</button>
        <button class="btn btn-primary" @onclick="NextStep">Next</button>
    </div>
}
else if (currentStep == 2)
{
    <h2>References</h2>
    @for (int i = 0; i < references.Count; i++)
    {
        var index = i;
        <div class="reference-entry">
            <h4>Reference @(index + 1)</h4>
            @if (references.Count > 2)
            {
                <button class="btn btn-danger btn-sm" @onclick="() => RemoveReference(index)">Remove</button>
            }
            <div class="form-group">
                <label>Name *</label>
                <input type="text" class="form-control" @bind="references[index].Name" />
            </div>
            <div class="form-group">
                <label>Relationship *</label>
                <input type="text" class="form-control" @bind="references[index].Relationship" />
            </div>
            <div class="form-group">
                <label>Email *</label>
                <input type="email" class="form-control" @bind="references[index].Email" />
            </div>
            <div class="form-group">
                <label>Phone *</label>
                <input type="tel" class="form-control" @bind="references[index].Phone" />
            </div>
        </div>
    }
    @if (references.Count < 3)
    {
        <button class="btn btn-secondary" @onclick="AddReference">Add Reference</button>
    }
    <div class="form-actions">
        <button class="btn btn-outline-secondary" @onclick="PreviousStep">Back</button>
        <button class="btn btn-primary" @onclick="NextStep">Next</button>
    </div>
}
else if (currentStep == 3)
{
    <h2>Cover Letter</h2>
    <div class="form-group">
        <textarea class="form-control cover-letter" @bind="coverLetter" @bind:event="oninput" maxlength="2000"></textarea>
        <div class="character-count">@coverLetter.Length / 2000 characters</div>
    </div>
    <div class="form-actions">
        <button class="btn btn-outline-secondary" @onclick="PreviousStep">Back</button>
        <button class="btn btn-primary" @onclick="NextStep">Next</button>
    </div>
}
else if (currentStep == 4)
{
    @if (isSubmitted)
    {
        <div class="confirmation">
            <h2>Application Submitted!</h2>
            <p>Thank you for your application. Your application ID is: <strong>@applicationId</strong></p>
        </div>
    }
    else
    {
        <h2>Review & Submit</h2>

        <div class="review-section">
            <h3>Personal Information <a href="#" @onclick="() => GoToStep(0)" @onclick:preventDefault>Edit</a></h3>
            <dl>
                <dt>Full Name</dt><dd>@fullName</dd>
                <dt>Email</dt><dd>@email</dd>
                <dt>Phone</dt><dd>@phone</dd>
                <dt>Address</dt><dd>@address</dd>
            </dl>
        </div>

        <div class="review-section">
            <h3>Work History <a href="#" @onclick="() => GoToStep(1)" @onclick:preventDefault>Edit</a></h3>
            @foreach (var entry in workEntries)
            {
                <div class="review-work-entry">
                    <strong>@entry.Title</strong> at <strong>@entry.Company</strong><br />
                    @entry.StartDate.ToString("MMM yyyy") &mdash;
                    @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")<br />
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p>@entry.Description</p>
                    }
                </div>
            }
        </div>

        <div class="review-section">
            <h3>References <a href="#" @onclick="() => GoToStep(2)" @onclick:preventDefault>Edit</a></h3>
            @foreach (var reference in references)
            {
                <div class="review-reference">
                    <strong>@reference.Name</strong> (@reference.Relationship)<br />
                    Email: @reference.Email | Phone: @reference.Phone
                </div>
            }
        </div>

        <div class="review-section">
            <h3>Cover Letter <a href="#" @onclick="() => GoToStep(3)" @onclick:preventDefault>Edit</a></h3>
            <p class="cover-letter-preview">@coverLetter</p>
        </div>

        <div class="form-actions">
            <button class="btn btn-outline-secondary" @onclick="PreviousStep">Back</button>
            <button class="btn btn-success" @onclick="SubmitApplication" disabled="@isProcessing">
                @if (isProcessing) { <span>Submitting...</span> } else { <span>Submit Application</span> }
            </button>
        </div>
    }
}

@code {
    private readonly string[] stepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };
    private int currentStep = 0;
    private string errorMessage = string.Empty;
    private bool isProcessing = false;
    private bool isSubmitted = false;
    private int applicationId;

    // Step 1 - Personal Info
    private string fullName = string.Empty;
    private string email = string.Empty;
    private string phone = string.Empty;
    private string address = string.Empty;

    // Step 2 - Work History
    private List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };

    // Step 3 - References
    private List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };

    // Step 4 - Cover Letter
    private string coverLetter = string.Empty;

    private string GetStepClass(int stepIndex)
    {
        if (stepIndex == currentStep) return "active";
        if (stepIndex < currentStep) return "completed";
        return "future";
    }

    private void GoToStep(int step)
    {
        if (step < currentStep)
        {
            currentStep = step;
            errorMessage = string.Empty;
        }
    }

    private async Task NextStep()
    {
        errorMessage = string.Empty;

        if (!ValidateCurrentStep())
            return;

        if (currentStep == 0)
        {
            isProcessing = true;
            try
            {
                var isValidEmail = await ApplicationService.ValidateEmailAsync(email);
                if (!isValidEmail)
                {
                    errorMessage = "The email address is not valid.";
                    isProcessing = false;
                    return;
                }
            }
            catch
            {
                errorMessage = "Unable to validate email. Please try again.";
                isProcessing = false;
                return;
            }
            isProcessing = false;
        }

        currentStep++;
    }

    private void PreviousStep()
    {
        if (currentStep > 0)
        {
            currentStep--;
            errorMessage = string.Empty;
        }
    }

    private bool ValidateCurrentStep()
    {
        switch (currentStep)
        {
            case 0:
                if (string.IsNullOrWhiteSpace(fullName) || string.IsNullOrWhiteSpace(email) ||
                    string.IsNullOrWhiteSpace(phone) || string.IsNullOrWhiteSpace(address))
                {
                    errorMessage = "All fields are required.";
                    return false;
                }
                return true;

            case 1:
                foreach (var entry in workEntries)
                {
                    if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title) ||
                        entry.StartDate == default)
                    {
                        errorMessage = "Company, job title, and start date are required for each position.";
                        return false;
                    }
                }
                return true;

            case 2:
                foreach (var reference in references)
                {
                    if (string.IsNullOrWhiteSpace(reference.Name) || string.IsNullOrWhiteSpace(reference.Relationship) ||
                        string.IsNullOrWhiteSpace(reference.Email) || string.IsNullOrWhiteSpace(reference.Phone))
                    {
                        errorMessage = "All fields are required for each reference.";
                        return false;
                    }
                }
                return true;

            case 3:
                if (string.IsNullOrWhiteSpace(coverLetter))
                {
                    errorMessage = "Cover letter is required.";
                    return false;
                }
                return true;

            default:
                return true;
        }
    }

    private void AddWorkEntry()
    {
        workEntries.Add(new WorkEntryModel());
    }

    private void RemoveWorkEntry(int index)
    {
        if (workEntries.Count > 1)
            workEntries.RemoveAt(index);
    }

    private void AddReference()
    {
        if (references.Count < 3)
            references.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (references.Count > 2)
            references.RemoveAt(index);
    }

    private async Task SubmitApplication()
    {
        isProcessing = true;
        errorMessage = string.Empty;

        try
        {
            var personal = new PersonalInfo(fullName, email, phone, address);
            var work = new WorkHistory(workEntries.Select(e => new WorkEntry(
                e.Company,
                e.Title,
                e.StartDate,
                e.IsCurrent ? null : e.EndDate,
                e.Description ?? string.Empty
            )).ToList());
            var refs = references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();
            var application = new JobApplication(personal, work, refs, coverLetter);

            applicationId = await ApplicationService.SubmitApplicationAsync(application);
            isSubmitted = true;
        }
        catch
        {
            errorMessage = "An error occurred while submitting your application. Please try again.";
        }
        finally
        {
            isProcessing = false;
        }
    }

    private class WorkEntryModel
    {
        public string Company { get; set; } = string.Empty;
        public string Title { get; set; } = string.Empty;
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string? Description { get; set; }
    }

    private class ReferenceModel
    {
        public string Name { get; set; } = string.Empty;
        public string Relationship { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
        public string Phone { get; set; } = string.Empty;
    }
}

