using System.Text.RegularExpressions;

namespace sv_5aabf268cc704760a03eed4ace83057c.Services;

public partial class ApplicationService : IApplicationService
{
    private static int _nextId = 1000;

    public Task<int> SubmitApplicationAsync(JobApplication application)
    {
        var id = Interlocked.Increment(ref _nextId);
        return Task.FromResult(id);
    }

    public Task<bool> ValidateEmailAsync(string email)
    {
        var isValid = !string.IsNullOrWhiteSpace(email) && EmailRegex().IsMatch(email);
        return Task.FromResult(isValid);
    }

    [GeneratedRegex(@"^[^@\s]+@[^@\s]+\.[^@\s]+$")]
    private static partial Regex EmailRegex();
}

